    for(int i = 0; i < n; ++i){
        auto [x, y, id] = t[i];

        // If it touches ANY axis, send it to the waiting room to be balanced later
        if(x == xmed || y == ymed){
            waitlist.push_back(t[i]);
        } 
        else {
            // It is strictly off-axis. Route it immediately.
            bool is_left = (x < xmed);
